 72→  },
 73→  title: {
 74→    color: colors.text,
 75→    fontSize: 22,
 76→    fontWeight: '800',
 77→    textAlign: 'center',
 78→  },
 79→  body: {
 80→    color: colors.textMuted,
 81→    fontSize: 14,
