10→export function FreedomWallScreen() {
11→  const {session} = useAuth();
12→  const token = session?.access_token;
13→
14→  const currentWeekQuery = useQuery({
15→    queryKey: ['freedom-current-week'],
16→    queryFn: () => mobileApi.getCurrentFreedomWallWeek(token),
17→  });
18→
19→  const weeksQuery = useQuery({
20→    queryKey: ['freedom-weeks'],
21→    queryFn: () => mobileApi.getFreedomWallWeeks(8, token),
22→  });
23→
24→  const activeWeekId = currentWeekQuery.data?.data?.id;
25→
26→  const itemsQuery = useQuery({
27→    queryKey: ['freedom-items', activeWeekId],
28→    enabled: Boolean(activeWeekId),
29→    queryFn: () => mobileApi.getFreedomWallItems(activeWeekId ?? '', {limit: 200}, token),
30→  });
