 19→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 20→
 21→type Props = CompositeScreenProps<
 22→  BottomTabScreenProps<MainTabParamList, 'Stories'>,
 23→  NativeStackScreenProps<RootStackParamList>
 24→>;
 25→
 26→const STATUS_FILTERS: Array<{label: string; value: StoryStatus | null}> = [
 27→  {label: 'All', value: null},
 28→  {label: 'Ongoing', value: 'ongoing'},
 29→  {label: 'Completed', value: 'completed'},
 30→  {label: 'Hiatus', value: 'hiatus'},
 31→];
 32→
 33→const getNextCursor = (lastPage: {data: StoryItem[]; hasMore?: boolean}) => {
 34→  if (!lastPage?.hasMore || !Array.isArray(lastPage.data) || lastPage.data.length === 0) {
 35→    return undefined;
 36→  }
 37→  return lastPage.data[lastPage.data.length - 1]?.created_at;
 38→};
 39→
 40→const StoryCard = ({
 41→  story,
 42→  onPress,
 43→}: {
 44→  story: StoryItem;
 45→  onPress: () => void;
 46→}) => (
 47→  <Pressable onPress={onPress} style={({pressed}) => [styles.storyCard, pressed && styles.storyCardPressed]}>
 48→    <Text style={styles.storyTitle}>{story.title}</Text>
 49→    <Text style={styles.storyMeta}>
 50→      {(story.users?.name || 'Unknown author') +
 51→        ` • ${story.status || 'ongoing'} • ${(story.vote_count || 0).toLocaleString()} votes`}
 52→    </Text>
 53→    {!!story.description && (
 54→      <Text style={styles.storyDescription} numberOfLines={3}>
 55→        {story.description}
 56→      </Text>
 57→    )}
 58→  </Pressable>
 59→);
 60→
 61→export function StoryBrowserScreen({navigation}: Props) {
 62→  const {session} = useAuth();
 63→  const token = session?.access_token;
 64→  const [statusFilter, setStatusFilter] = useState<StoryStatus | null>(null);
 65→
 66→  const storiesQuery = useInfiniteQuery({
 67→    queryKey: ['stories-browser', statusFilter, token],
 68→    queryFn: ({pageParam}) =>
 69→      storyApi.getStories({
 70→        status: statusFilter,
 71→        before: pageParam ?? null,
 72→        limit: 12,
 73→        token,
 74→      }),
 75→    initialPageParam: null as string | null,
 76→    getNextPageParam: lastPage => getNextCursor(lastPage),
 77→  });
 78→
 79→  const stories = useMemo(
 80→    () => storiesQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
 81→    [storiesQuery.data?.pages],
 82→  );
 83→
 84→  return (
 85→    <Screen scroll={false}>
 86→      <View style={styles.header}>
 87→        <Text style={styles.title}>Stories</Text>
 88→        <View style={styles.headerActions}>
 89→          {token ? (
 90→            <>
 91→              <PrimaryButton
 92→                label="Library"
 93→                onPress={() => navigation.navigate('StoryLibrary')}
 94→                kind="secondary"
 95→              />
 96→              <PrimaryButton
 97→                label="My Stories"
 98→                onPress={() => navigation.navigate('StoryDashboard')}
 99→                kind="secondary"
100→              />
101→              <PrimaryButton
102→                label="Write"
103→                onPress={() => navigation.navigate('StoryEditor', {})}
104→              />
105→            </>
106→          ) : (
107→            <Text style={styles.metaHint}>Log in to create and manage stories.</Text>
108→          )}
109→        </View>
110→      </View>
111→
112→      <View style={styles.filterRow}>
113→        {STATUS_FILTERS.map(filter => (
114→          <Pressable
115→            key={filter.label}
116→            onPress={() => setStatusFilter(filter.value)}
117→            style={[
118→              styles.filterChip,
119→              statusFilter === filter.value && styles.filterChipActive,
120→            ]}>
121→            <Text
122→              style={[
123→                styles.filterText,
124→                statusFilter === filter.value && styles.filterTextActive,
125→              ]}>
126→              {filter.label}
127→            </Text>
128→          </Pressable>
129→        ))}
130→      </View>
131→
132→      {storiesQuery.isLoading ? (
133→        <View style={styles.loading}>
134→          <ActivityIndicator color={colors.accent} />
135→          <Text style={styles.metaHint}>Loading stories...</Text>
136→        </View>
137→      ) : (
138→        <FlatList
139→          data={stories}
140→          keyExtractor={item => item.id}
141→          onEndReachedThreshold={0.3}
142→          onEndReached={() => {
143→            if (storiesQuery.hasNextPage && !storiesQuery.isFetchingNextPage) {
144→              storiesQuery.fetchNextPage();
145→            }
146→          }}
147→          ListEmptyComponent={<Text style={styles.metaHint}>No stories found.</Text>}
148→          renderItem={({item}) => (
149→            <StoryCard
150→              story={item}
151→              onPress={() => navigation.navigate('StoryDetail', {storyId: item.id})}
152→            />
153→          )}
154→          ListFooterComponent={
155→            storiesQuery.isFetchingNextPage ? (
156→              <View style={styles.loadingMore}>
157→                <ActivityIndicator color={colors.accent} />
158→              </View>
159→            ) : null
160→          }
161→        />
162→      )}
163→    </Screen>
164→  );
165→}
