 28→export function StoryChapterEditorScreen({route, navigation}: Props) {
 29→  const {storyId, chapterId} = route.params;
 30→  const {session} = useAuth();
 31→  const token = session?.access_token ?? '';
 32→  const editorRef = useRef<RichEditor>(null);
 33→
 34→  const chapterQuery = useQuery({
 35→    queryKey: ['story-chapter', storyId, chapterId, token],
 36→    queryFn: () => storyApi.getChapter(storyId, chapterId, token),
 37→  });
 38→
 39→  const [chapterTitle, setChapterTitle] = useState('');
 40→  const [html, setHtml] = useState('');
 41→
 42→  useEffect(() => {
 43→    if (chapterQuery.data) {
 44→      setChapterTitle(chapterQuery.data.title || '');
 45→      const text = extractPlainTextFromLexical(chapterQuery.data.content);
 46→      setHtml(text);
 47→      editorRef.current?.setContentHTML(text);
 48→    }
 49→  }, [chapterQuery.data]);
 50→
 51→  const canSave = useMemo(
 52→    () => chapterTitle.trim().length > 0 && stripHtml(html).length > 0,
 53→    [chapterTitle, html],
 54→  );
 55→
 56→  const updateMutation = useMutation({
 57→    mutationFn: (status?: string) =>
 58→      storyApi.updateChapter(token, storyId, chapterId, {
 59→        title: chapterTitle.trim() || 'Untitled Chapter',
 60→        content: toLexicalFromPlainText(stripHtml(html)),
 61→        status,
 62→      }),
 63→    onSuccess: () => {
 64→      queryClient.invalidateQueries({queryKey: ['story', storyId]});
 65→      queryClient.invalidateQueries({queryKey: ['story-chapter', storyId, chapterId]});
 66→    },
 67→    onError: error => {
