101→      <RichEditor
102→        ref={editorRef}
103→        style={styles.editor}
104→        placeholder="Start writing your chapter..."
105→        initialHeight={260}
106→        onChange={setHtml}
107→        editorStyle={richEditorStyle}
108→      />
109→      <RichToolbar
110→        editor={editorRef}
111→        actions={[
112→          actions.setBold,
113→          actions.setItalic,
114→          actions.setUnderline,
115→          actions.insertBulletsList,
116→          actions.insertOrderedList,
117→        ]}
118→        selectedIconTint={colors.accent}
119→        iconTint={colors.textMuted}
120→        style={styles.toolbar}
121→      />
122→
123→      <PrimaryButton
