 23→export function StoryChapterReaderScreen({route, navigation}: Props) {
 24→  const {storyId, chapterId} = route.params;
 25→  const {session} = useAuth();
 26→  const token = session?.access_token ?? '';
 27→  const [commentBody, setCommentBody] = useState('');
 28→
 29→  const chapterQuery = useQuery({
 30→    queryKey: ['story-chapter', storyId, chapterId, token],
 31→    queryFn: () => storyApi.getChapter(storyId, chapterId, token),
 32→  });
 33→
 34→  const commentsQuery = useQuery({
 35→    queryKey: ['chapter-comments', chapterId, token],
 36→    queryFn: () => storyApi.getChapterComments(chapterId, null, token),
 37→  });
 38→
 39→  const progressMutation = useMutation({
 40→    mutationFn: (position: number) =>
 41→      storyApi.saveReadingProgress(token, storyId, chapterId, position),
 42→  });
 43→
 44→  const addCommentMutation = useMutation({
 45→    mutationFn: () =>
 46→      storyApi.addChapterComment(token, chapterId, {
 47→        content: commentBody.trim(),
 48→        paragraph_index: null,
 49→      }),
 50→    onSuccess: () => {
 51→      queryClient.invalidateQueries({queryKey: ['chapter-comments', chapterId, token]});
 52→      setCommentBody('');
 53→    },
 54→  });
 55→
 56→  const chapterText = useMemo(
 57→    () => extractPlainTextFromLexical(chapterQuery.data?.content),
 58→    [chapterQuery.data?.content],
 59→  );
 60→
 61→  return (
 62→    <Screen scroll={false}>
 63→      {chapterQuery.isLoading ? (
 64→        <View style={styles.loading}>
 65→          <ActivityIndicator color={colors.accent} />
 66→          <Text style={styles.meta}>Loading chapter...</Text>
 67→        </View>
 68→      ) : !chapterQuery.data ? (
 69→        <Text style={styles.error}>Chapter not found.</Text>
 70→      ) : (
 71→        <>
 72→          <Text style={styles.title}>
 73→            {`Ch. ${chapterQuery.data.chapter_number || '?'}: ${chapterQuery.data.title}`}
 74→          </Text>
 75→
 76→          <ScrollView
 77→            style={styles.reader}
 78→            contentContainerStyle={styles.readerContent}
 79→            onMomentumScrollEnd={event => {
 80→              const offsetY = event.nativeEvent.contentOffset.y;
 81→              const contentHeight = event.nativeEvent.contentSize.height;
 82→              const viewportHeight = event.nativeEvent.layoutMeasurement.height;
 83→              const scrollable = Math.max(0, contentHeight - viewportHeight);
 84→              const ratio = scrollable > 0 ? Math.min(1, offsetY / scrollable) : 0;
 85→              if (token) {
 86→                progressMutation.mutate(ratio);
 87→              }
 88→            }}>
 89→            <Text style={styles.chapterBody}>{chapterText || 'No content available.'}</Text>
 90→          </ScrollView>
 91→
 92→          <View style={styles.navRow}>
 93→            {chapterQuery.data.prev_chapter ? (
 94→              <PrimaryButton
 95→                label={`Prev: ${chapterQuery.data.prev_chapter.title}`}
 96→                onPress={() =>
 97→                  navigation.replace('StoryChapterReader', {
 98→                    storyId,
 99→                    chapterId: chapterQuery.data?.prev_chapter?.id || '',
100→                  })
101→                }
102→                kind="secondary"
103→              />
104→            ) : (
105→              <View />
106→            )}
107→            {chapterQuery.data.next_chapter ? (
108→              <PrimaryButton
109→                label={`Next: ${chapterQuery.data.next_chapter.title}`}
110→                onPress={() =>
111→                  navigation.replace('StoryChapterReader', {
112→                    storyId,
113→                    chapterId: chapterQuery.data?.next_chapter?.id || '',
114→                  })
115→                }
116→              />
117→            ) : (
118→              <View />
119→            )}
120→          </View>
121→
122→          <View style={styles.commentsCard}>
123→            <Text style={styles.commentsTitle}>Comments</Text>
124→            {Array.isArray(commentsQuery.data?.data) && commentsQuery.data?.data?.length > 0 ? (
125→              commentsQuery.data.data.slice(0, 8).map((comment: any, idx: number) => (
126→                <View key={comment?.id || idx} style={styles.commentRow}>
127→                  <Text style={styles.commentAuthor}>
128→                    {comment?.users?.name || comment?.user_name || 'Reader'}
129→                  </Text>
130→                  <Text style={styles.commentBody}>{comment?.content || comment?.comment || ''}</Text>
131→                </View>
132→              ))
133→            ) : (
134→              <Text style={styles.meta}>No comments yet.</Text>
135→            )}
136→            {token && (
137→              <>
138→                <TextInput
139→                  value={commentBody}
140→                  onChangeText={setCommentBody}
141→                  placeholder="Add a comment"
142→                  placeholderTextColor={colors.textMuted}
143→                  style={styles.commentInput}
144→                  multiline
145→                />
146→                <PrimaryButton
147→                  label="Submit Comment"
148→                  onPress={() => addCommentMutation.mutate()}
149→                  loading={addCommentMutation.isPending}
150→                  disabled={commentBody.trim().length === 0}
151→                />
152→              </>
153→            )}
154→          </View>
155→        </>
156→      )}
157→    </Screen>
158→  );
159→}
