 22→
 23→const TAG_SUGGESTIONS = [
 24→  'Fantasy',
 25→  'Romance',
 26→  'Sci-Fi',
 27→  'Mystery',
 28→  'Thriller',
 29→  'Horror',
 30→  'Adventure',
