import {CompositeScreenProps} from '@react-navigation/native';
import {NativeStackScreenProps} from '@react-navigation/native-stack';
import {Screen} from '../../components/Screen';
import {PrimaryButton} from '../../components/PrimaryButton';
import {storyApi, type StoryItem, type StoryStatus} from '../../lib/api/storyApi';
import {useAuth} from '../../features/auth/AuthProvider';
import {useTheme} from '../../theme/ThemeProvider';
import type {MainTabParamList, RootStackParamList} from '../../navigation/types';

type Props = CompositeScreenProps<
  BottomTabScreenProps<MainTabParamList, 'Stories'>,
  NativeStackScreenProps<RootStackParamList>
>;

const STATUS_FILTERS: Array<{label: string; value: StoryStatus | null}> = [
  {label: 'All', value: null},
  {label: 'Ongoing', value: 'ongoing'},
  {label: 'Completed', value: 'completed'},
  {label: 'Hiatus', value: 'hiatus'},
];

const getNextCursor = (lastPage: {data: StoryItem[]; hasMore?: boolean}) => {
  if (!lastPage?.hasMore || !Array.isArray(lastPage.data) || lastPage.data.length === 0) {
    return undefined;
  }
  return lastPage.data[lastPage.data.length - 1]?.created_at;
};

const StoryCard = ({
  story,
  onPress,
}: {
  story: StoryItem;
  onPress: () => void;
}) => {
  const {colors} = useTheme();
  return (
    <Pressable
      onPress={onPress}
      style={({pressed}) => [
        styles.storyCard,
        {backgroundColor: colors.bgElevated, borderColor: colors.borderLight},
        pressed && styles.storyCardPressed,
      ]}>
      <Text style={[styles.storyTitle, {color: colors.textPrimary}]}>{story.title}</Text>
      <Text style={[styles.storyMeta, {color: colors.textMuted}]}>
        {(story.users?.name || 'Unknown author') +
          ` • ${story.status || 'ongoing'} • ${(story.vote_count || 0).toLocaleString()} votes`}
      </Text>
      {!!story.description && (
        <Text style={[styles.storyDescription, {color: colors.textPrimary}]} numberOfLines={3}>
          {story.description}
        </Text>
      )}
    </Pressable>
  );
};

export function StoryBrowserScreen({navigation}: Props) {
  const {colors} = useTheme();
  const {session} = useAuth();
  const token = session?.access_token;
  const [statusFilter, setStatusFilter] = useState<StoryStatus | null>(null);

  const storiesQuery = useInfiniteQuery({
    queryKey: ['stories-browser', statusFilter, token],
    queryFn: ({pageParam}) =>
      storyApi.getStories({
        status: statusFilter,
        before: pageParam ?? null,
        limit: 12,
        token,
      }),
    initialPageParam: null as string | null,
    getNextPageParam: lastPage => getNextCursor(lastPage),
  });

  const stories = useMemo(
    () => storiesQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
    [storiesQuery.data?.pages],
  );

  return (
    <Screen scroll={false}>
      <View style={styles.header}>
        <Text style={[styles.title, {color: colors.textPrimary}]}>Stories</Text>
        <View style={styles.headerActions}>
          {token ? (
            <>
              <PrimaryButton
                label="Library"
                onPress={() => navigation.navigate('StoryLibrary')}
                kind="secondary"
              />
              <PrimaryButton
                label="My Stories"
                onPress={() => navigation.navigate('StoryDashboard')}
                kind="secondary"
              />
              <PrimaryButton
                label="Write"
                onPress={() => navigation.navigate('StoryEditor', {})}
              />
            </>
          ) : (
            <Text style={[styles.metaHint, {color: colors.textMuted}]}>Log in to create and manage stories.</Text>
          )}
        </View>
      </View>

      <View style={styles.filterRow}>
        {STATUS_FILTERS.map(filter => (
          <Pressable
            key={filter.label}
            onPress={() => setStatusFilter(filter.value)}
            style={[
              styles.filterChip,
              {
                borderColor: statusFilter === filter.value ? colors.accentAmber : colors.borderLight,
                backgroundColor: statusFilter === filter.value ? colors.accentAmber : colors.bgElevated,
              },
            ]}>
            <Text
              style={[
                styles.filterText,
                {
                  color: statusFilter === filter.value ? '#FFFFFF' : colors.textMuted,
                  fontWeight: statusFilter === filter.value ? '700' : 'normal',
                },
              ]}>
              {filter.label}
            </Text>
          </Pressable>
        ))}
      </View>

      {storiesQuery.isLoading ? (
        <View style={styles.loading}>
          <ActivityIndicator color={colors.accentAmber} />
          <Text style={[styles.metaHint, {color: colors.textMuted}]}>Loading stories...</Text>
        </View>
      ) : (
        <FlatList
          data={stories}
          keyExtractor={item => item.id}
          onEndReachedThreshold={0.3}
          onEndReached={() => {
            if (storiesQuery.hasNextPage && !storiesQuery.isFetchingNextPage) {
              storiesQuery.fetchNextPage();
            }
          }}
          ListEmptyComponent={<Text style={[styles.metaHint, {color: colors.textMuted}]}>No stories found.</Text>}
          renderItem={({item}) => (
            <StoryCard
              story={item}
              onPress={() => navigation.navigate('StoryDetail', {storyId: item.id})}
            />
          )}
          ListFooterComponent={
            storiesQuery.isFetchingNextPage ? (
              <View style={styles.loadingMore}>
                <ActivityIndicator color={colors.accentAmber} />
              </View>
            ) : null
          }
        />
      )}
    </Screen>
  );
}

const styles = StyleSheet.create({
