const getNext = (page: {data: StoryItem[]; hasMore?: boolean}) => {
  if (!page.hasMore || page.data.length === 0) {
    return undefined;
  }
  return page.data[page.data.length - 1]?.updated_at;
};

export function StoryDashboardScreen({navigation}: Props) {
  const {colors} = useTheme();
  const {session} = useAuth();
  const token = session?.access_token ?? '';
  const queryClient = useQueryClient();

  const myStoriesQuery = useInfiniteQuery({
    queryKey: ['stories-dashboard', token],
    enabled: token.length > 0,
    queryFn: ({pageParam}) => storyApi.getMyStories(token, {limit: 10, before: pageParam ?? null}),
    initialPageParam: null as string | null,
    getNextPageParam: page => getNext(page),
  });

  const deleteMutation = useMutation({
    mutationFn: (storyId: string) => storyApi.deleteStory(token, storyId),
    onSuccess: () => {
      queryClient.invalidateQueries({queryKey: ['stories-dashboard', token]});
      queryClient.invalidateQueries({queryKey: ['stories-browser']});
    },
  });

  const stories = useMemo(
    () => myStoriesQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
    [myStoriesQuery.data?.pages],
  );

  const onDelete = (storyId: string, title: string) => {
    Alert.alert('Delete story', `Delete "${title}"?`, [
      {text: 'Cancel', style: 'cancel'},
      {text: 'Delete', style: 'destructive', onPress: () => deleteMutation.mutate(storyId)},
    ]);
  };

  return (
    <Screen scroll={false}>
      <View style={styles.header}>
        <Text style={[styles.title, {color: colors.textPrimary}]}>My Stories</Text>
        <PrimaryButton
          label="New Story"
          onPress={() => navigation.navigate('StoryEditor', {})}
        />
      </View>

      {!token ? (
        <Text style={[styles.meta, {color: colors.textMuted}]}>Login required.</Text>
      ) : myStoriesQuery.isLoading ? (
        <View style={styles.loading}>
          <ActivityIndicator color={colors.accentAmber} />
          <Text style={[styles.meta, {color: colors.textMuted}]}>Loading stories...</Text>
        </View>
      ) : (
        <FlatList
          data={stories}
          keyExtractor={item => item.id}
          onEndReachedThreshold={0.3}
          onEndReached={() => {
            if (myStoriesQuery.hasNextPage && !myStoriesQuery.isFetchingNextPage) {
              myStoriesQuery.fetchNextPage();
            }
          }}
          ListEmptyComponent={<Text style={[styles.meta, {color: colors.textMuted}]}>No stories yet.</Text>}
          renderItem={({item}) => (
            <View
              style={[
                styles.card,
                {borderColor: colors.borderLight, backgroundColor: colors.bgElevated},
              ]}>
              <Pressable
                onPress={() => navigation.navigate('StoryChapterManager', {storyId: item.id})}
                style={({pressed}) => [styles.storyTouch, pressed && styles.storyPressed]}>
                <Text style={[styles.storyTitle, {color: colors.textPrimary}]}>{item.title}</Text>
                <Text style={[styles.storyMeta, {color: colors.textMuted}]}>
                  {(item.status || 'ongoing').toString()}
                  {` • ${(item.chapters?.length || 0).toString()} chapters`}
                </Text>
              </Pressable>
              <View style={styles.cardActions}>
                <PrimaryButton
                  label="Edit"
                  onPress={() => navigation.navigate('StoryEditor', {storyId: item.id})}
                  kind="secondary"
                />
                <PrimaryButton
                  label="Delete"
                  onPress={() => onDelete(item.id, item.title)}
                  kind="danger"
                  loading={deleteMutation.isPending}
                />
              </View>
            </View>
          )}
        />
      )}
    </Screen>
  );
}

