import React, {useMemo, useState} from 'react';
import {
  ActivityIndicator,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';
import {useMutation, useQuery} from '@tanstack/react-query';
import {NativeStackScreenProps} from '@react-navigation/native-stack';
import {Screen} from '../../components/Screen';
import {PrimaryButton} from '../../components/PrimaryButton';
import {storyApi} from '../../lib/api/storyApi';
import {extractPlainTextFromLexical} from '../../lib/content/lexical';
import {useAuth} from '../../features/auth/AuthProvider';
import {queryClient} from '../../lib/queryClient';
import {useTheme} from '../../theme/ThemeProvider';
import type {RootStackParamList} from '../../navigation/types';

type Props = NativeStackScreenProps<RootStackParamList, 'StoryChapterReader'>;

export function StoryChapterReaderScreen({route, navigation}: Props) {
  const {colors} = useTheme();
  const {storyId, chapterId} = route.params;
  const {session} = useAuth();
  const token = session?.access_token ?? '';
  const [commentBody, setCommentBody] = useState('');

  const chapterQuery = useQuery({
    queryKey: ['story-chapter', storyId, chapterId, token],
    queryFn: () => storyApi.getChapter(storyId, chapterId, token),
  });

  const commentsQuery = useQuery({
    queryKey: ['chapter-comments', chapterId, token],
    queryFn: () => storyApi.getChapterComments(chapterId, null, token),
  });

  const progressMutation = useMutation({
    mutationFn: (position: number) =>
      storyApi.saveReadingProgress(token, storyId, chapterId, position),
  });

  const addCommentMutation = useMutation({
    mutationFn: () =>
      storyApi.addChapterComment(token, chapterId, {
        content: commentBody.trim(),
        paragraph_index: null,
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({queryKey: ['chapter-comments', chapterId, token]});
      setCommentBody('');
    },
  });

  const chapterText = useMemo(
    () => extractPlainTextFromLexical(chapterQuery.data?.content),
    [chapterQuery.data?.content],
  );

  return (
    <Screen scroll={false}>
      {chapterQuery.isLoading ? (
        <View style={styles.loading}>
          <ActivityIndicator color={colors.accentAmber} />
          <Text style={[styles.meta, {color: colors.textMuted}]}>Loading chapter...</Text>
        </View>
      ) : !chapterQuery.data ? (
        <Text style={[styles.error, {color: colors.danger}]}>Chapter not found.</Text>
      ) : (
        <>
          <Text style={[styles.title, {color: colors.textPrimary}]}>
            {`Ch. ${chapterQuery.data.chapter_number || '?'}: ${chapterQuery.data.title}`}
          </Text>

          <ScrollView
            style={[
              styles.reader,
              {borderColor: colors.borderLight, backgroundColor: colors.bgElevated},
            ]}
            contentContainerStyle={styles.readerContent}
            onMomentumScrollEnd={event => {
              const offsetY = event.nativeEvent.contentOffset.y;
              const contentHeight = event.nativeEvent.contentSize.height;
              const viewportHeight = event.nativeEvent.layoutMeasurement.height;
              const scrollable = Math.max(0, contentHeight - viewportHeight);
              const ratio = scrollable > 0 ? Math.min(1, offsetY / scrollable) : 0;
              if (token) {
                progressMutation.mutate(ratio);
              }
            }}>
            <Text style={[styles.chapterBody, {color: colors.textPrimary}]}>{chapterText || 'No content available.'}</Text>
          </ScrollView>

          <View style={styles.navRow}>
            {chapterQuery.data.prev_chapter ? (
              <PrimaryButton
                label={`Prev: ${chapterQuery.data.prev_chapter.title}`}
                onPress={() =>
                  navigation.replace('StoryChapterReader', {
                    storyId,
                    chapterId: chapterQuery.data?.prev_chapter?.id || '',
                  })
                }
                kind="secondary"
              />
            ) : (
              <View />
            )}
            {chapterQuery.data.next_chapter ? (
              <PrimaryButton
                label={`Next: ${chapterQuery.data.next_chapter.title}`}
                onPress={() =>
                  navigation.replace('StoryChapterReader', {
                    storyId,
                    chapterId: chapterQuery.data?.next_chapter?.id || '',
                  })
                }
              />
            ) : (
              <View />
            )}
          </View>

          <View
            style={[
              styles.commentsCard,
              {borderColor: colors.borderLight, backgroundColor: colors.bgElevated},
            ]}>
            <Text style={[styles.commentsTitle, {color: colors.textPrimary}]}>Comments</Text>
            {Array.isArray(commentsQuery.data?.data) && commentsQuery.data?.data?.length > 0 ? (
              commentsQuery.data.data.slice(0, 8).map((comment: any, idx: number) => (
                <View
                  key={comment?.id || idx}
                  style={[styles.commentRow, {borderTopColor: colors.borderLight}]}>
                  <Text style={[styles.commentAuthor, {color: colors.textPrimary}]}>
                    {comment?.users?.name || comment?.user_name || 'Reader'}
                  </Text>
                  <Text style={[styles.commentBody, {color: colors.textMuted}]}>{comment?.content || comment?.comment || ''}</Text>
                </View>
              ))
            ) : (
              <Text style={[styles.meta, {color: colors.textMuted}]}>No comments yet.</Text>
            )}
            {token && (
              <>
                <TextInput
                  value={commentBody}
                  onChangeText={setCommentBody}
                  placeholder="Add a comment"
                  placeholderTextColor={colors.textMuted}
                  style={[
                    styles.commentInput,
                    {
                      borderColor: colors.borderLight,
                      backgroundColor: colors.bgSecondary,
                      color: colors.textPrimary,
                    },
                  ]}
                  multiline
                />
                <PrimaryButton
                  label="Submit Comment"
                  onPress={() => addCommentMutation.mutate()}
                  loading={addCommentMutation.isPending}
                  disabled={commentBody.trim().length === 0}
                />
              </>
            )}
          </View>
        </>
      )}
    </Screen>
  );
}

